import React, { useState, useEffect, useRef, useCallback } from 'react';
import { View, StyleSheet, Pressable, Animated, Dimensions, StatusBar, Vibration } from 'react-native';
import { SafeImage } from '@/components/SafeImage';
import { ThemedText } from '@/components/ThemedText';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { useNavigation, useRoute } from '@react-navigation/native';
import { LinearGradient } from 'expo-linear-gradient';
import { Audio } from 'expo-av';
import { useAuth } from '@/hooks/useAuth';
import { useApi } from '@/hooks/useApi';
import socketService from '@/services/socket';

const { height: SCREEN_HEIGHT } = Dimensions.get('window');

interface CallData {
  channelName: string;
  token: string;
  appId: string;
  uid: number;
  callType: string;
  callerId: string;
  targetUserId: string;
}

export default function VoiceCallScreen() {
  const insets = useSafeAreaInsets();
  const navigation = useNavigation<any>();
  const route = useRoute<any>();
  const { userId, userName, userPhoto, isIncoming, callData: incomingCallData, callerId, callAccepted } = route.params || {};
  const { token: authToken, user } = useAuth();
  const { post } = useApi();

  const [callStatus, setCallStatus] = useState<'initializing' | 'connecting' | 'ringing' | 'connected' | 'ended' | 'failed' | 'declined' | 'busy' | 'missed'>('initializing');
  const [callData, setCallData] = useState<CallData | null>(incomingCallData || null);

  const fadeAnim = useRef(new Animated.Value(0)).current;
  const ringtoneRef = useRef<Audio.Sound | null>(null);

  const stopRingtone = useCallback(async () => {
    try {
      if (ringtoneRef.current) {
        await ringtoneRef.current.stopAsync();
        await ringtoneRef.current.unloadAsync();
        ringtoneRef.current = null;
      }
      Vibration.cancel();
    } catch (err) {
      console.log('Audio Cleanup Error:', err);
    }
  }, []);

  const playRingtone = useCallback(async () => {
    try {
      await stopRingtone();

      // Configure audio session first
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: false,
        playsInSilentModeIOS: true,
        staysActiveInBackground: true,
        shouldRouteThroughEarpieceAndroid: false,
      });

      // Selection: Receiver hears WAV melody, Caller hears MP3 dialing
      const source = isIncoming 
        ? { uri: 'https://assets.mixkit.co/active_storage/sfx/1354/1354-preview.mp3' } 
        : { uri: 'https://www.soundjay.com/phone/phone-calling-1.mp3' };

      const { sound } = await Audio.Sound.createAsync(
        source,
        { shouldPlay: true, isLooping: true, volume: 1.0 }
      );

      ringtoneRef.current = sound;
      if (isIncoming) {
        Vibration.vibrate([500, 1000, 500], true);
      }
    } catch (err) {
      console.error('Audio Playback Error:', err);
    }
  }, [isIncoming, stopRingtone]);

  const initiateCall = useCallback(async () => {
    if (!authToken || !userId) {
      setCallStatus('failed');
      return;
    }
    try {
      setCallStatus('connecting');
      const response = await post<{ callData: CallData }>('/agora/call/initiate', {
        targetUserId: userId,
        callType: 'voice',
      }, authToken);

      if (response.success && response.data?.callData) {
        setCallData(response.data.callData);
        setCallStatus('ringing');

        socketService.initiateCall({
          targetUserId: userId,
          callData: response.data.callData,
          callerInfo: { 
            name: user?.name || 'User', 
            photo: user?.photos?.[0]?.url || '', 
            id: user?.id || '' 
          }
        });
      }
    } catch (error) {
      setCallStatus('failed');
    }
  }, [authToken, userId, post, user]);

  useEffect(() => {
    Animated.timing(fadeAnim, { toValue: 1, duration: 500, useNativeDriver: true }).start();

    if (isIncoming && incomingCallData) {
      setCallStatus(callAccepted ? 'connected' : 'ringing');
    } else {
      initiateCall();
    }

    socketService.onCallAccepted(() => {
      setCallStatus('connected');
    });

    socketService.onCallEnded(() => {
      setCallStatus('ended');
      setTimeout(() => navigation.goBack(), 1000);
    });

    return () => {
      stopRingtone();
      socketService.off('call:accepted');
      socketService.off('call:ended');
    };
  }, [isIncoming, incomingCallData, callAccepted, initiateCall, navigation, stopRingtone, fadeAnim]);

  useEffect(() => {
    if (callStatus === 'ringing') {
      playRingtone();
    } else if (['connected', 'ended', 'failed'].includes(callStatus)) {
      stopRingtone();
    }
  }, [callStatus, playRingtone, stopRingtone]);

  const handleEndCall = () => {
    setCallStatus('ended');
    stopRingtone();
    socketService.endCall({ 
      targetUserId: isIncoming ? callerId : userId, 
      callType: 'audio' 
    });
    navigation.goBack();
  };

  const getStatusText = () => {
    switch (callStatus) {
      case 'connecting': return 'Connecting...';
      case 'ringing': return isIncoming ? 'Incoming Call' : 'Ringing...';
      case 'connected': return 'Connected';
      case 'ended': return 'Call Ended';
      case 'failed': return 'Call Failed';
      default: return 'Initializing...';
    }
  };

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />
      <LinearGradient
        colors={['#0f0c29', '#302b63', '#24243e']}
        style={StyleSheet.absoluteFill}
      />

      <Animated.View style={[styles.centerSection, { opacity: fadeAnim }]}>
        <View style={styles.avatarSection}>
          <View style={styles.avatarWrapper}>
            <SafeImage
              source={{ uri: userPhoto || 'https://via.placeholder.com/150' }}
              style={styles.avatar}
            />
          </View>
        </View>

        <ThemedText style={styles.userName}>{userName || 'Unknown'}</ThemedText>
        <ThemedText style={styles.statusText}>{getStatusText()}</ThemedText>
      </Animated.View>

      <View style={[styles.controlsSection, { paddingBottom: insets.bottom + 40 }]}>
        <Pressable style={styles.endCallBtn} onPress={handleEndCall}>
          <Ionicons name="call" size={32} color="#FFF" style={{ transform: [{ rotate: '135deg' }] }} />
        </Pressable>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#0f0c29',
  },
  centerSection: {
    flex: 1,
    alignItems: 'center',
    paddingTop: SCREEN_HEIGHT * 0.15,
  },
  avatarSection: {
    width: 160,
    height: 160,
    marginBottom: 20,
    justifyContent: 'center',
    alignItems: 'center',
  },
  avatarWrapper: {
    width: 140,
    height: 140,
    borderRadius: 70,
    overflow: 'hidden',
    borderWidth: 3,
    borderColor: 'rgba(255,255,255,0.2)',
  },
  avatar: {
    width: '100%',
    height: '100%',
  },
  userName: {
    fontSize: 28,
    fontWeight: '700',
    color: '#FFF',
    marginBottom: 10,
  },
  statusText: {
    fontSize: 18,
    color: 'rgba(255,255,255,0.6)',
  },
  controlsSection: {
    alignItems: 'center',
  },
  endCallBtn: {
    width: 75,
    height: 75,
    borderRadius: 37.5,
    backgroundColor: '#FF3B30',
    justifyContent: 'center',
    alignItems: 'center',
  },
});
